// Parse CSV và format Telegram message
const csv = $input.first().json.data || '';
const lines = csv.trim().split('\n').filter(l => l.trim());
const today = new Date().toLocaleDateString('vi-VN', {timeZone: 'Asia/Ho_Chi_Minh'});

// Lấy dòng cuối (ngày mới nhất)
const lastLine = lines[lines.length - 1]?.split(',') || [];
const headers = lines[0]?.split(',') || [];

const getValue = (key) => {
  const idx = headers.findIndex(h => h.toLowerCase().includes(key.toLowerCase()));
  return idx >= 0 ? (lastLine[idx] || '—').replace(/"/g, '').trim() : '—';
};

const msg = [
  `🚀 *Daily SGN Report ${today}*`,
  ``,
  `📦 Orders: ${getValue('order') || getValue('đơn')}`,
  `✅ FR: ${getValue('fr') || getValue('fulfillment')}`,
  `⚡ AR: ${getValue('ar') || getValue('accept')}`,
  `💰 CPO: ${getValue('cpo')}`,
  ``,
  `_Auto-report by Pulu_`
].join('\n');

return [{ json: { message: msg } }];
